/* ── Expandable Panel ── */
.expandable-panel {
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    border: none;
    background: #f8f9fa;
    cursor: pointer;
    font-weight: 500;
    font-size: 0.9rem;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-chevron {
    transition: transform 0.2s;
    font-size: 0.85rem;
}

.panel-chevron.open {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #e0e0e0;
}

/* ── Status badges ── */
.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 500;
