{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_be68cc6a4d2c4a7ab1864c0cb7a1b5cf.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar" aria-label="Settings sections">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)"
                    aria-current="@(section == _activeSection ? "page" : null)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-notification @(_toastIsError ? "toast-error" : "toast-success")" role="alert">
                <span class="toast-icon">@(_toastIsError ? "✗" : "✓")</span>
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ── Confirmation Modal ── *@
@if (_showConfirmDialog)
{
    <div class="modal-backdrop" @onclick="CancelRevoke">
        <div class="confirm-dialog" @onclick:stopPropagation="true">
            <h6>Revoke Session</h6>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?
                This will sign out that device immediately.</p>
            <div class="confirm-actions">
                <button class="btn btn-secondary btn-sm" @onclick="CancelRevoke">Cancel</button>
                <button class="btn btn-danger btn-sm" @onclick="ConfirmRevoke">Revoke</button>
            </div>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;

    // Profile
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Notifications
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showConfirmDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData("Profile");
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (section == _activeSection) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionData(section);
        _loading = false;
    }

    private async Task LoadSectionData(string section)
    {
        switch (section)
        {
            case "Profile":
                _savedProfile = await SettingsService.GetProfileAsync();
                ApplyProfile(_savedProfile);
                break;
            case "Notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _allChannels = new List<string>(prefs.MutedChannels.Count > 0
                    ? prefs.MutedChannels
                    : ["general", "announcements", "random"]);
                _mutedChannels = new HashSet<string>(prefs.MutedChannels);
                break;
            case "Security":
                _security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _security.TwoFactorEnabled;
                _passwordPanelOpen = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    // ── Profile ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Profile</h4>
            <p class="section-subtitle">Manage your public profile information.</p>

            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">@(_displayName.Length > 0 ? _displayName[0] : '?')</div>
                    }
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" placeholder="https://..." />
                </div>
            </div>

            <div class="form-group">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="form-group">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="action-bar">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications ──

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Notifications</h4>
            <p class="section-subtitle">Choose how you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <span>Email Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_emailNotifications" />
                        <span class="slider"></span>
                    </label>
                </div>
                <div class="toggle-row">
                    <span>Push Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_pushNotifications" />
                        <span class="slider"></span>
                    </label>
                </div>
                <div class="toggle-row">
                    <span>Weekly Digest</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_weeklyDigest" />
                        <span class="slider"></span>
                    </label>
                </div>
            </div>

            <h6 class="mt-4 mb-2">Muted Channels</h6>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="(e) => ToggleMute(ch, (bool)(e.Value ?? false))" />
                        <span class="channel-name">#@ch</span>
                        <span class="badge @(_mutedChannels.Contains(ch) ? "bg-secondary" : "bg-success") ms-auto">
                            @(_mutedChannels.Contains(ch) ? "Muted" : "Active")
                        </span>
                    </label>
                }
            </div>

            <div class="action-bar">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </section>
    };

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Security</h4>
            <p class="section-subtitle">Manage passwords, two-factor authentication, and active sessions.</p>

            @* Change Password Panel *@
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span class="panel-chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">Confirm Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="text-muted small">Last changed: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
                        }
                        <button class="btn btn-primary btn-sm" @onclick="UpdatePassword">Update Password</button>
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="toggle-row mt-3">
                <div>
                    <span>Two-Factor Authentication</span>
                    <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="slider"></span>
                </label>
            </div>

            @* Active Sessions *@
            <h6 class="mt-4 mb-2">Active Sessions</h6>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-sm sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session == _security.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions found.</p>
            }
        </section>
    };

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        ShowToast("Password updated successfully.");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showConfirmDialog = true;
    }

    private void CancelRevoke()
    {
        _showConfirmDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
        }
        _showConfirmDialog = false;
        _sessionToRevoke = null;
        ShowToast("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ── Appearance ──

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Appearance</h4>
            <p class="section-subtitle">Customize how the app looks and feels.</p>

            <div class="form-group">
                <label class="form-label">Theme</label>
                <div class="radio-group">
                    @foreach (var t in _themes)
                    {
                        var theme = t;
                        <label class="radio-option @(_theme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            @theme
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label class="form-label">Font Size</label>
                <div class="radio-group">
                    @foreach (var fs in _fontSizes)
                    {
                        var size = fs;
                        <label class="radio-option @(_fontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            @size
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label class="form-label">Language</label>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="toggle-row">
                <span>Compact Mode</span>
                <label class="switch">
                    <input type="checkbox" @bind="_compactMode" />
                    <span class="slider"></span>
                </label>
            </div>

            @* Live Preview *@
            <div class="preview-area @GetPreviewClasses()">
                <h6 class="preview-title">Live Preview</h6>
                <div class="preview-card">
                    <p class="preview-heading">Sample Heading</p>
                    <p class="preview-text">This is how your content will look with the current settings. The quick brown fox jumps over the lazy dog.</p>
                    <div class="preview-actions">
                        <span class="preview-btn primary">Primary</span>
                        <span class="preview-btn secondary">Secondary</span>
                    </div>
                </div>
                <div class="preview-meta">
                    Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </div>
            </div>

            <div class="action-bar">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme switch
        {
            "Dark" => "preview-dark",
            "Light" => "preview-light",
            _ => "preview-system"
        });
        classes.Add(_fontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        ShowToast("Appearance settings saved.");
    }

    // ── Helpers ──

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙"
    };

    private async void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();
        await Task.Delay(3000);
        _toastVisible = false;
        StateHasChanged();
    }
}
