toolArgs.file_text:
/* ── Layout ── */
.settings-dashboard {
    display: flex;
    min-height: 80vh;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #e0e0e0;
    padding: 1rem 0;
    display: flex;
    flex-direction: column;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #333;
    font-size: 0.95rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
    font-size: 0.9rem;
    color: #555;
    transition: background 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.05rem;
    width: 1.4rem;
    text-align: center;
}

/* ── Content ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.loading-spinner {
    display: flex;
    justify-content: center;
    padding: 4rem 0;
}

.settings-section {
    max-width: 640px;
}

.section-title {
    margin: 0 0 0.25rem;
    font-weight: 600;
}

.section-subtitle {
    color: #6c757d;
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
}

/* ── Forms ── */
.form-group {
    margin-bottom: 1rem;
}

.form-label {
    font-weight: 500;
    font-size: 0.85rem;
    color: #444;
    margin-bottom: 0.3rem;
}

.action-bar {
    display: flex;
    gap: 0.5rem;
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid #eee;
}

/* ── Avatar ── */
.avatar-area {
    display: flex;
    align-items: center;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #e9ecef;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
    font-weight: 600;
    color: #6c757d;
}

.avatar-url-display {
    flex: 1;
}

/* ── Toggle switch ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.switch {
    position: relative;
    display: inline-block;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    transition: 0.2s;
    border-radius: 24px;
}

.slider::before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    transition: 0.2s;
    border-radius: 50%;
}

.switch input:checked + .slider {
    background-color: #0d6efd;
}

.switch input:checked + .slider::before {
    transform: translateX(20px);
}

/* ── Channels ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0;
